import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.ObjectInputStream;

public class InsecureDeserializationExample {

    public static void main(String[] args) {
        String serializedObject = "rO0ABXNyAClqYXZhLnV0aWwuRGVmYXVsdFZhbHVlAAAAAAAAAAECAAVYAANtAA9pbnNlcnQgc3RyaW5nAA==";

        Object deserializedObject = deserializeObject(serializedObject);

        System.out.println(deserializedObject);
    }

    private static Object deserializeObject(String serializedObject) {
        try {
            byte[] bytes = javax.xml.bind.DatatypeConverter.parseBase64Binary(serializedObject);
            ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(bytes));
            return ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
            return null;
        }
    }
}

